import abc

class Logger(abc.ABC):
    @abc.abstractmethod
    def log_message(self, message: str):
        pass

class DataProcessor(abc.ABC):
    @abc.abstractmethod
    def process_data(self, data):
        pass

class SystemComponent(Logger, DataProcessor):
    def __init__(self, component_id: str):
        self.component_id = component_id

    def log_message(self, message: str):
        print(f"[{self.component_id} - LOG]: {message}")

    def process_data(self, data):
        processed_data = f"Processed: {data}"
        self.log_message(f"Data '{data}' processed into '{processed_data}'")
        return processed_data

if __name__ == "__main__":
    component = SystemComponent("ServiceA")
    component.log_message("Starting up component...")
    result = component.process_data({"input_key": "raw_value"})
    component.log_message(f"Final result: {result}")

    # Demonstrating the type of the component
    print(f"\nIs component an instance of Logger? {isinstance(component, Logger)}")
    print(f"Is component an instance of DataProcessor? {isinstance(component, DataProcessor)}")
